enum NpcSpriteId {
    NPC_SPR_MOM = 0,
    NPC_SPR_OAK = 1,
    NPC_SPR_BLUE = 2,
    NPC_SPR_GRAMPS = 3,
    NPC_SPR_NURSE = 4,
    NPC_SPR_CLERK = 5,
    NPC_SPR_GIRL = 6,
    NPC_SPR_BRUNETTE = 7,
    NPC_SPR_LITTLE_BOY = 8,
    NPC_SPR_LITTLE_GIRL = 9,
    NPC_SPR_FISHER = 10,
    NPC_SPR_GENTLEMAN = 11,
    NPC_SPR_POKE_BALL = 12,
    NPC_SPR_SUPER_NERD = 13,
    NPC_SPR_COOLTRAINER_M = 14,
    NPC_SPR_COUNT = 15
};

inline const OwPlayerFrame* getNpcSpritePtr(int spriteId, int dir = 0, int walkFrame = 0) {
    // 걷는 포즈(컷신 슬라이드 중 toggle) — 현재 up walk만 데이터 존재(오박사/블루).
    if (walkFrame && dir == 1) {
        switch (spriteId) {
        case 1: return &SPR_OAK_UP_WALK;
        case 2: return &SPR_BLUE_UP_WALK;
        default: break;  // 나머지 NPC는 walk 데이터 없음 → 아래 up idle로 폴백
        }
    }
    if (dir == 1) {  // up idle
        switch (spriteId) {
        case 0: return &SPR_MOM_UP;
        case 1: return &SPR_OAK_UP;
        case 2: return &SPR_BLUE_UP;
        case 3: return &SPR_GRAMPS_UP;
        case 4: return &SPR_NURSE_UP;
        case 5: return &SPR_CLERK_UP;
        case 6: return &SPR_GIRL_UP;
        case 7: return &SPR_BRUNETTE_UP;
        case 8: return &SPR_LITTLE_BOY_UP;
        case 9: return &SPR_LITTLE_GIRL_UP;
        case 10: return &SPR_FISHER_UP;
        case 11: return &SPR_GENTLEMAN_UP;
        case 12: return &SPR_POKE_BALL_UP;
        case 13: return &SPR_SUPER_NERD_UP;
        case 14: return &SPR_COOLTRAINER_M_UP;
        default: return &SPR_MOM_UP;
        }
    }
    switch (spriteId) {  // down idle (default)
    case 0: return &SPR_MOM;
    case 1: return &SPR_OAK;
    case 2: return &SPR_BLUE;
    case 3: return &SPR_GRAMPS;
    case 4: return &SPR_NURSE;
    case 5: return &SPR_CLERK;
    case 6: return &SPR_GIRL;
    case 7: return &SPR_BRUNETTE;
    case 8: return &SPR_LITTLE_BOY;
    case 9: return &SPR_LITTLE_GIRL;
    case 10: return &SPR_FISHER;
    case 11: return &SPR_GENTLEMAN;
    case 12: return &SPR_POKE_BALL;
    case 13: return &SPR_SUPER_NERD;
    case 14: return &SPR_COOLTRAINER_M;
    default: return &SPR_MOM;
    }
}

